var VAULT_ADDRESSES = new Set(Object.values(VAULTS).map((v) => v.address.toLowerCase()));
var VAULT_ADDRESS_TO_SYMBOL = new Map(
  Object.values(VAULTS).map((v) => [v.address.toLowerCase(), v.symbol])
);
var VAULT_ASSET_PATTERNS = {
  yoETH: /yoETH|^ETH$|WETH|stETH|wstETH|cbETH|rETH|weETH|frxETH|oETH/i,
  yoUSD: /yoUSD|^USD$|USDC|USDT|DAI|USDS|gtUSDC/i,
  yoEUR: /yoEUR|^EUR$|EURC/i,
  yoBTC: /yoBTC|^BTC$|WBTC|cbBTC|LBTC/i,
  yoGOLD: /yoGOLD|^GOLD$|XAUT/i
};
function resolveVaultType(opportunity) {
  if (opportunity.identifier) {
    const match = VAULT_ADDRESS_TO_SYMBOL.get(opportunity.identifier.toLowerCase());
    if (match) return match;
  }
  const tokens = opportunity.tokens ?? [];
  for (const token of tokens) {
    const match = VAULT_ADDRESS_TO_SYMBOL.get(token.address.toLowerCase());
    if (match) return match;
  }
  for (const token of tokens) {
    for (const [vaultName, pattern] of Object.entries(VAULT_ASSET_PATTERNS)) {
      if (pattern.test(token.symbol)) return vaultName;
    }
  }
  return null;
}
function getPendingRewardSets(chainRewards) {
  const opportunityIds = /* @__PURE__ */ new Set();
  const vaultTypes = /* @__PURE__ */ new Set();
  if (!chainRewards?.rewards) return { opportunityIds, vaultTypes };
  for (const reward of chainRewards.rewards) {
    if (!reward.breakdowns) continue;
    for (const breakdown of reward.breakdowns) {
      const claimable = BigInt(breakdown.amount) - BigInt(breakdown.claimed);
      if (claimable <= 0n) continue;
      if (breakdown.opportunity?.id) {
        opportunityIds.add(breakdown.opportunity.id);
      }
      const vt = resolveVaultType(breakdown.opportunity);
      if (vt) {
        vaultTypes.add(vt);
      }
    }
  }
  return { opportunityIds, vaultTypes };
}
function campaignHasPendingRewards(campaign, pendingRewards) {
  const opp = campaign.Opportunity;
  if (!opp) return false;
  const isPrimaryYoVault = opp.identifier && VAULT_ADDRESSES.has(opp.identifier.toLowerCase());
  if (isPrimaryYoVault) {
    return pendingRewards.vaultTypes.has(resolveVaultType(opp) ?? "");
  }
  return pendingRewards.opportunityIds.has(opp.id ?? "");
}
